const settings = $('Load Global Settings').first().json ?? {};
return [{
  json: {
    template_key: settings.gmail_test_email_template_key || 'shoe_tag_pigeon_hole',
    recipient_first_name: 'Steve',
    recipient_last_name: 'Short',
    sender_name: settings.email_sender_name || 'Steve Short',
    reply_to: settings.email_reply_to || 'members.avondaleltc@gmail.com',
  },
}];

const item = $input.first().json;
const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const sql = `with candidates as (
  select 1 as priority,
    "First name" as first_name,
    "Last name" as last_name,
    "Email address" as email_address,
    "Address 1" as address_1,
    town,
    postcode
  from public.raw_contacts
  where "First name" = ${sqlLiteral(item.recipient_first_name)}
    and "Last name" = ${sqlLiteral(item.recipient_last_name)}
  union all
  select 2 as priority,
    "First name" as first_name,
    "Last name" as last_name,
    "Email address" as email_address,
    "Address 1" as address_1,
    "Town" as town,
    "Postcode" as postcode
  from public.raw_members
  where "First name" = ${sqlLiteral(item.recipient_first_name)}
    and "Last name" = ${sqlLiteral(item.recipient_last_name)}
)
select first_name, last_name, email_address, address_1, town, postcode
from candidates
where email_address is not null and email_address <> ''
order by priority
limit 1;`;
return [{ json: { ...item, sql } }];

const item = $('Editable Send Inputs').first().json;
const sqlLiteral = (value) => {
  if (value === null || value === undefined || value === '') return 'NULL';
  return "'" + String(value).replace(/'/g, "''") + "'";
};
const sql = `select template_key, subject_template, text_template, html_template
from public.email_templates
where template_key = ${sqlLiteral(item.template_key)}
  and is_active = true
order by id desc
limit 1;`;
return [{ json: { template_key: item.template_key, sql } }];

const input = $('Editable Send Inputs').first().json;
const recipient = $('Load Recipient Record').first()?.json ?? {};
const template = $('Load Email Template').first()?.json ?? {};
if (!recipient.email_address) {
  throw new Error(`No email address found for ${input.recipient_first_name} ${input.recipient_last_name}`);
}
if (!template.template_key) {
  throw new Error(`Email template ${input.template_key} was not found`);
}
const tokenMap = {
  '{{$json.first_name}}': recipient.first_name ?? '',
  '{{$json.last_name}}': recipient.last_name ?? '',
  '{{$json.email_address}}': recipient.email_address ?? '',
  '{{$json.address_1}}': recipient.address_1 ?? '',
  '{{$json.town}}': recipient.town ?? '',
  '{{$json.postcode}}': recipient.postcode ?? '',
  '{{$json.contact.first_name}}': recipient.first_name ?? '',
  '{{$json.contact.last_name}}': recipient.last_name ?? '',
  '{{$json.contact.email_address}}': recipient.email_address ?? '',
  '{{$json.contact.address_1}}': recipient.address_1 ?? '',
  '{{$json.contact.town}}': recipient.town ?? '',
  '{{$json.contact.postcode}}': recipient.postcode ?? '',
  '{{$json.member.first_name}}': recipient.first_name ?? '',
  '{{$json.member.last_name}}': recipient.last_name ?? '',
  '{{$json.member.email_address}}': recipient.email_address ?? '',
  '{{first_name}}': recipient.first_name ?? '',
  '{{last_name}}': recipient.last_name ?? '',
  '{{email_address}}': recipient.email_address ?? '',
  '{{address_1}}': recipient.address_1 ?? '',
  '{{town}}': recipient.town ?? '',
  '{{postcode}}': recipient.postcode ?? '',
  '<first name>': recipient.first_name ?? '',
  '<last name>': recipient.last_name ?? '',
  '<email address>': recipient.email_address ?? '',
  '{contact.first_name}': recipient.first_name ?? '',
  '{contact.last_name}': recipient.last_name ?? '',
  '{contact.email_address}': recipient.email_address ?? '',
  '{contact.address_1}': recipient.address_1 ?? '',
  '{contact.town}': recipient.town ?? '',
  '{contact.postcode}': recipient.postcode ?? '',
  '{member.first_name}': recipient.first_name ?? '',
  '{member.last_name}': recipient.last_name ?? '',
  '{member.email_address}': recipient.email_address ?? '',
};
const applyTokens = (value) => {
  let rendered = String(value ?? '');
  for (const [token, replacement] of Object.entries(tokenMap)) {
    rendered = rendered.split(token).join(String(replacement));
  }
  return rendered.trim();
};
const bodySource = template.text_template ?? template.html_template ?? '';
return [{
  json: {
    to_email: recipient.email_address,
    sender_name: input.sender_name,
    reply_to: input.reply_to,
    template_key: template.template_key,
    rendered_subject: applyTokens(template.subject_template ?? 'Message from Avondale about your tags'),
    rendered_message: applyTokens(bodySource),
    email_type: template.html_template && !template.text_template ? 'html' : 'text',
    recipient_first_name: recipient.first_name,
    recipient_last_name: recipient.last_name,
  },
}];
